import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { 
  FaUser, 
  FaEdit, 
  FaSave, 
  FaTimes,
  FaCalendarAlt,
  FaHeart,
  FaPhone,
  FaMapMarkerAlt,
  FaTint,
  FaAllergies,
  FaBirthdayCake,
  FaUserMd,
  FaCamera,
  FaPlus,
  FaUpload,
  FaMale,
  FaFemale,
  FaRulerVertical,
  FaWeight,
  FaExclamationTriangle,
  FaUserFriends,
  FaEnvelope,
  FaClipboardList,
  FaClock
} from 'react-icons/fa';

const Profile = () => {
  const { t } = useTranslation();
  const [isEditing, setIsEditing] = useState(false);
  const [activeTab, setActiveTab] = useState('profile');
  
  // Enhanced patient profile data
  const [profileData, setProfileData] = useState({
    // Personal Information
    name: 'Rajesh Kumar',
    age: 35,
    gender: 'Male',
    phone: '+91 98765 43210',
    email: 'rajesh.kumar@email.com',
    address: 'House No. 123, Sector 4, Chandigarh, Punjab - 160012',
    date_of_birth: '1988-03-15',
    
    // Medical Information
    blood_group: 'B+',
    height: '5\'8" (173 cm)',
    weight: '72 kg',
    allergies: 'Penicillin, Dust, Pollen',
    current_conditions: 'Hypertension, Type 2 Diabetes',
    
    // Emergency Contact
    emergency_contact_name: 'Sunita Kumar',
    emergency_contact_relation: 'Wife',
    emergency_contact_phone: '+91 87654 32109',
    
    // Profile Picture
    avatar: null
  });

  // Recent appointments data
  const recentAppointments = [
    {
      id: 'APT001',
      doctor: 'Dr. Priya Sharma',
      specialty: 'Cardiology',
      date: '2024-01-15',
      time: '10:30 AM',
      status: 'Completed',
      diagnosis: 'Regular checkup - Normal'
    },
    {
      id: 'APT002', 
      doctor: 'Dr. Harpreet Singh',
      specialty: 'General Medicine',
      date: '2024-01-08',
      time: '02:00 PM',
      status: 'Completed',
      diagnosis: 'Fever, prescribed medication'
    },
    {
      id: 'APT003',
      doctor: 'Dr. Sunita Devi',
      specialty: 'Dermatology',
      date: '2024-01-20',
      time: '11:00 AM',
      status: 'Upcoming',
      diagnosis: 'Scheduled'
    }
  ];

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setProfileData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSave = () => {
    setIsEditing(false);
    console.log('Profile saved:', profileData);
  };

  const handleAvatarChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        setProfileData(prev => ({
          ...prev,
          avatar: e.target.result
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  // Patient Header Component
  const PatientHeader = () => (
    <div className="relative bg-gradient-to-r from-blue-600 to-purple-600 rounded-t-xl p-6 text-white">
      <div className="absolute inset-0 bg-black bg-opacity-10 rounded-t-xl"></div>
      
      <div className="relative flex items-center space-x-4">
        {/* Avatar Section */}
        <div className="relative">
          <div className="w-20 h-20 rounded-full bg-white bg-opacity-20 flex items-center justify-center overflow-hidden border-4 border-white border-opacity-30">
            {profileData.avatar ? (
              <img 
                src={profileData.avatar} 
                alt="Profile" 
                className="w-full h-full object-cover"
              />
            ) : (
              <FaUser className="text-3xl text-white" />
            )}
          </div>
          
          <button 
            className="absolute -bottom-1 -right-1 w-7 h-7 bg-blue-500 rounded-full flex items-center justify-center shadow-lg hover:bg-blue-600 transition-colors"
            onClick={() => document.getElementById('avatar-upload').click()}
          >
            <FaCamera className="text-xs text-white" />
          </button>
          <input
            type="file"
            id="avatar-upload"
            accept="image/*"
            onChange={handleAvatarChange}
            className="hidden"
          />
        </div>

        {/* Patient Info */}
        <div className="flex-1">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold">{profileData.name}</h1>
              <div className="flex items-center space-x-4 mt-1 text-blue-100">
                <span className="flex items-center space-x-1">
                  <FaBirthdayCake className="text-sm" />
                  <span>Age {profileData.age}</span>
                </span>
                <span className="flex items-center space-x-1">
                  {profileData.gender === 'Male' ? 
                    <FaMale className="text-sm" /> : 
                    <FaFemale className="text-sm" />
                  }
                  <span>{profileData.gender}</span>
                </span>
              </div>
            </div>
            
            <button
              onClick={() => setIsEditing(!isEditing)}
              className="bg-white bg-opacity-20 hover:bg-opacity-30 transition-all duration-200 px-4 py-2 rounded-lg flex items-center space-x-2 backdrop-blur-sm"
            >
              {isEditing ? <FaTimes className="text-sm" /> : <FaEdit className="text-sm" />}
              <span className="text-sm font-medium">
                {isEditing ? 'Cancel' : 'Edit Profile'}
              </span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  // Modern Tab Navigation
  const TabNavigation = () => (
    <div className="bg-white border-b border-gray-200 px-6">
      <div className="flex space-x-8">
        <button
          onClick={() => setActiveTab('profile')}
          className={`py-4 px-2 border-b-2 font-semibold text-sm transition-colors duration-200 ${
            activeTab === 'profile'
              ? 'border-blue-500 text-blue-600'
              : 'border-transparent text-gray-500 hover:text-gray-700'
          }`}
        >
          <div className="flex items-center space-x-2">
            <FaUser className="text-sm" />
            <span>Profile Information</span>
          </div>
        </button>
        <button
          onClick={() => setActiveTab('appointments')}
          className={`py-4 px-2 border-b-2 font-semibold text-sm transition-colors duration-200 ${
            activeTab === 'appointments'
              ? 'border-blue-500 text-blue-600'
              : 'border-transparent text-gray-500 hover:text-gray-700'
          }`}
        >
          <div className="flex items-center space-x-2">
            <FaCalendarAlt className="text-sm" />
            <span>Appointment History</span>
          </div>
        </button>
      </div>
    </div>
  );

  // Information Field Component
  const InfoField = ({ icon: Icon, label, value, name, type = "text", editable = true }) => (
    <div className="space-y-2">
      <label className="flex items-center space-x-2 text-sm font-medium text-gray-700">
        <Icon className="text-blue-500 text-sm" />
        <span>{label}</span>
      </label>
      {isEditing && editable ? (
        <input
          type={type}
          name={name}
          value={value}
          onChange={handleInputChange}
          className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all duration-200"
        />
      ) : (
        <div className="px-4 py-3 bg-gray-50 rounded-lg text-gray-900 min-h-[48px] flex items-center">
          {value || 'Not specified'}
        </div>
      )}
    </div>
  );

  // Personal Information Section
  const PersonalInformationCard = () => (
    <div className="bg-white rounded-xl shadow-lg border border-gray-100 overflow-hidden">
      <div className="bg-gradient-to-r from-blue-50 to-indigo-50 px-6 py-4 border-b border-gray-100">
        <h3 className="text-lg font-semibold text-gray-800 flex items-center space-x-2">
          <FaUser className="text-blue-600" />
          <span>Personal Information</span>
        </h3>
      </div>
      
      <div className="p-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <InfoField
            icon={FaUser}
            label="Full Name"
            value={profileData.name}
            name="name"
          />
          <InfoField
            icon={FaBirthdayCake}
            label="Age"
            value={profileData.age}
            name="age"
            type="number"
          />
          <InfoField
            icon={profileData.gender === 'Male' ? FaMale : FaFemale}
            label="Gender"
            value={profileData.gender}
            name="gender"
          />
          <InfoField
            icon={FaPhone}
            label="Contact Number"
            value={profileData.phone}
            name="phone"
            type="tel"
          />
          <InfoField
            icon={FaEnvelope}
            label="Email Address"
            value={profileData.email}
            name="email"
            type="email"
          />
          <InfoField
            icon={FaCalendarAlt}
            label="Date of Birth"
            value={profileData.date_of_birth}
            name="date_of_birth"
            type="date"
          />
        </div>
        
        <div className="mt-6">
          <InfoField
            icon={FaMapMarkerAlt}
            label="Address"
            value={profileData.address}
            name="address"
          />
        </div>
      </div>
    </div>
  );

  // Medical Information Section
  const MedicalInformationCard = () => (
    <div className="bg-white rounded-xl shadow-lg border border-gray-100 overflow-hidden">
      <div className="bg-gradient-to-r from-red-50 to-pink-50 px-6 py-4 border-b border-gray-100">
        <h3 className="text-lg font-semibold text-gray-800 flex items-center space-x-2">
          <FaHeart className="text-red-600" />
          <span>Medical Information</span>
        </h3>
      </div>
      
      <div className="p-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <InfoField
            icon={FaTint}
            label="Blood Group"
            value={profileData.blood_group}
            name="blood_group"
          />
          <InfoField
            icon={FaRulerVertical}
            label="Height"
            value={profileData.height}
            name="height"
          />
          <InfoField
            icon={FaWeight}
            label="Weight"
            value={profileData.weight}
            name="weight"
          />
          <InfoField
            icon={FaAllergies}
            label="Known Allergies"
            value={profileData.allergies}
            name="allergies"
          />
        </div>
        
        <div className="mt-6">
          <InfoField
            icon={FaExclamationTriangle}
            label="Current Medical Conditions"
            value={profileData.current_conditions}
            name="current_conditions"
          />
        </div>
      </div>
    </div>
  );

  // Emergency Contact Section
  const EmergencyContactCard = () => (
    <div className="bg-white rounded-xl shadow-lg border border-gray-100 overflow-hidden">
      <div className="bg-gradient-to-r from-orange-50 to-yellow-50 px-6 py-4 border-b border-gray-100">
        <h3 className="text-lg font-semibold text-gray-800 flex items-center space-x-2">
          <FaUserFriends className="text-orange-600" />
          <span>Emergency Contact</span>
        </h3>
      </div>
      
      <div className="p-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <InfoField
            icon={FaUser}
            label="Contact Name"
            value={profileData.emergency_contact_name}
            name="emergency_contact_name"
          />
          <InfoField
            icon={FaUserFriends}
            label="Relationship"
            value={profileData.emergency_contact_relation}
            name="emergency_contact_relation"
          />
          <InfoField
            icon={FaPhone}
            label="Phone Number"
            value={profileData.emergency_contact_phone}
            name="emergency_contact_phone"
            type="tel"
          />
        </div>
      </div>
    </div>
  );

  // Profile Tab Content
  const renderProfileTab = () => (
    <div className="space-y-6 p-6">
      <PersonalInformationCard />
      <MedicalInformationCard />
      <EmergencyContactCard />
      
      {isEditing && (
        <div className="flex justify-center pt-4">
          <button
            onClick={handleSave}
            className="bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 text-white px-8 py-3 rounded-lg font-semibold shadow-lg transform hover:scale-105 transition-all duration-200 flex items-center space-x-2"
          >
            <FaSave className="text-sm" />
            <span>Save Changes</span>
          </button>
        </div>
      )}
    </div>
  );

  // Enhanced Appointments Tab
  const renderAppointmentsTab = () => (
    <div className="p-6">
      <div className="space-y-4">
        {recentAppointments.map((appointment) => (
          <div key={appointment.id} className="bg-white rounded-xl shadow-lg border border-gray-100 overflow-hidden hover:shadow-xl transition-shadow duration-200">
            <div className="p-6">
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center space-x-3 mb-3">
                    <div className="w-12 h-12 bg-gradient-to-r from-blue-100 to-purple-100 rounded-full flex items-center justify-center">
                      <FaUserMd className="text-blue-600 text-lg" />
                    </div>
                    <div>
                      <h4 className="font-semibold text-gray-900">{appointment.doctor}</h4>
                      <p className="text-sm text-gray-600">{appointment.specialty}</p>
                    </div>
                  </div>
                  
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
                    <div className="flex items-center space-x-2">
                      <FaCalendarAlt className="text-blue-500" />
                      <span className="text-gray-700">{appointment.date}</span>
                    </div>
                    <div className="flex items-center space-x-2">
                      <FaClock className="text-green-500" />
                      <span className="text-gray-700">{appointment.time}</span>
                    </div>
                    <div className="flex items-center space-x-2">
                      <FaClipboardList className="text-purple-500" />
                      <span className="text-gray-700">{appointment.diagnosis}</span>
                    </div>
                    <div>
                      <span className={`px-3 py-1 rounded-full text-xs font-medium ${
                        appointment.status === 'Completed' 
                          ? 'bg-green-100 text-green-800'
                          : appointment.status === 'Upcoming'
                          ? 'bg-blue-100 text-blue-800'
                          : 'bg-gray-100 text-gray-800'
                      }`}>
                        {appointment.status}
                      </span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
      
      {recentAppointments.length === 0 && (
        <div className="text-center py-12">
          <FaCalendarAlt className="mx-auto text-gray-400 text-4xl mb-4" />
          <p className="text-gray-600">No appointments found</p>
        </div>
      )}
    </div>
  );

  // Floating Action Button
  const FloatingActionButton = () => (
    <div className="fixed bottom-24 right-6 z-50">
      <div className="relative group">
        <button className="w-14 h-14 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 text-white rounded-full shadow-lg hover:shadow-xl transform hover:scale-110 transition-all duration-200 flex items-center justify-center group">
          <FaPlus className="text-xl group-hover:rotate-45 transition-transform duration-200" />
        </button>
        
        <div className="absolute bottom-16 right-0 opacity-0 group-hover:opacity-100 group-hover:translate-y-0 translate-y-4 transition-all duration-200 space-y-2">
          <button 
            onClick={() => setIsEditing(!isEditing)}
            className="flex items-center space-x-3 bg-white hover:bg-gray-50 text-gray-700 px-4 py-2 rounded-lg shadow-lg border border-gray-200 whitespace-nowrap"
          >
            <FaEdit className="text-blue-500" />
            <span className="text-sm font-medium">Edit Profile</span>
          </button>
          
          <button className="flex items-center space-x-3 bg-white hover:bg-gray-50 text-gray-700 px-4 py-2 rounded-lg shadow-lg border border-gray-200 whitespace-nowrap">
            <FaUpload className="text-green-500" />
            <span className="text-sm font-medium">Upload Reports</span>
          </button>
          
          <button 
            onClick={() => document.getElementById('avatar-upload').click()}
            className="flex items-center space-x-3 bg-white hover:bg-gray-50 text-gray-700 px-4 py-2 rounded-lg shadow-lg border border-gray-200 whitespace-nowrap"
          >
            <FaCamera className="text-purple-500" />
            <span className="text-sm font-medium">Change Photo</span>
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50 pb-32">
      <div className="max-w-4xl mx-auto pt-8 px-4">
        <PatientHeader />
        <TabNavigation />
        <div className="bg-white rounded-b-xl shadow-lg">
          {activeTab === 'profile' && renderProfileTab()}
          {activeTab === 'appointments' && renderAppointmentsTab()}
        </div>
      </div>
      
      <FloatingActionButton />
    </div>
  );
};

export default Profile;
